def fuzzy_and(val1, val2):
    return min(val1, val2)

def fuzzy_or(val1, val2):
    return max(val1, val2)

# Doc 1: Very relevant for A, slightly for B
d1 = {"science": 0.9, "history": 0.1}

# User Search: "science AND history"
score_and = fuzzy_and(d1["science"], d1["history"])
score_or = fuzzy_or(d1["science"], d1["history"])

print(f"AND Match: {score_and}")
print(f"OR Match: {score_or}")
